// Step 1: fetch all transactions in the window (paged), find failures,
// group them, fetch BindTransactionLogsHistory for ONE representative per
// group, extract the error line, and build a Teams digest. All in one Code
// node using this.helpers.httpRequest (avoids the HTTP node gzip/socket bug).

const input = $input.first().json;

let session;
try {
  session = typeof input.sessionJson === 'string' ? JSON.parse(input.sessionJson) : input.sessionJson;
} catch (e) { throw new Error('sessionJson is not valid JSON.'); }
if (!session.cookies || !session.token) throw new Error('session.json missing cookies or token. Re-run login.');

const cookie = session.cookies.map(c => `${c.name}=${c.value}`).join('; ');
const token = session.token;
const base = (session.portalUrl || 'https://integration.commonwellalliance.lkopera.com/').replace(/\/$/, '');
const gridUrl = base + '/TransactionLogs/BindTransactionLogs';
const histUrl = base + '/TransactionLogs/BindTransactionLogsHistory';

const windowMinutes = input.windowMinutes || 30;
const pageSize = input.pageSize || 100;
const portalTz = input.portalTimeZone || 'America/New_York';
const enc = encodeURIComponent;

function fmtInTz(d, tz) {
  const parts = new Intl.DateTimeFormat('en-US', { timeZone: tz, year:'numeric',month:'numeric',day:'numeric',hour:'numeric',minute:'2-digit',second:'2-digit',hour12:true }).formatToParts(d);
  const p = {}; for (const x of parts) p[x.type] = x.value;
  return `${p.month}/${p.day}/${p.year} ${p.hour}:${p.minute}:${p.second} ${p.dayPeriod}`;
}
const now = new Date();
const fromDate = fmtInTz(new Date(now.getTime() - windowMinutes*60000), portalTz);
const toDate = fmtInTz(now, portalTz);

async function post(url, bodyObj) {
  const body = Object.keys(bodyObj).map(k => `${enc(k)}=${enc(bodyObj[k])}`).join('&');
  const r = await this.helpers.httpRequest({
    method:'POST', url,
    headers:{ 'Cookie':cookie, 'Content-Type':'application/x-www-form-urlencoded; charset=UTF-8', 'X-Requested-With':'XMLHttpRequest', 'Accept':'*/*', 'Origin':base, 'Referer':base+'/TransactionLogs/index' },
    body, json:false
  });
  let resp = r;
  if (typeof resp === 'string') {
    const t = resp.trim();
    if (t.startsWith('<')) throw new Error('Got HTML instead of JSON — session expired. Re-run login.');
    resp = JSON.parse(t);
  }
  return resp;
}

// --- fetch failures directly by status (ServerError + ClientError) ---
// Far lighter than pulling everything: the portal filters server-side.
function gridBody(page, statusFilter) {
  return { sort:'transactionId-asc', page:String(page), pageSize:String(pageSize), group:'', filter:'', Status:statusFilter, FromDate:fromDate, ToDate:toDate, organizationId:'', MemberId:'', TransactionType:'', TransactionId:'', before:'', after:'', __RequestVerificationToken:token };
}

async function fetchAllForStatus(statusFilter) {
  let out = [];
  let pg = 1;
  const f = await post.call(this, gridUrl, gridBody(pg, statusFilter));
  const tot = (f && (f.Total||f.total)) || 0;
  out = out.concat((f && (f.Data||f.data)) || []);
  while (out.length < tot && pg < 200) {
    pg++;
    const nx = await post.call(this, gridUrl, gridBody(pg, statusFilter));
    const nr = (nx && (nx.Data||nx.data)) || [];
    if (!nr.length) break;
    out = out.concat(nr);
  }
  return out;
}

const errorStatuses = ['ServerError', 'ClientError'];
let failures = [];
const diag = { fromDate, toDate, perStatus: {} };
for (const st of errorStatuses) {
  const got = await fetchAllForStatus.call(this, st);
  diag.perStatus[st] = got.length;
  failures = failures.concat(got);
}

// DIAGNOSTIC: if nothing came back by status filter, also do one 'All' query
// to see whether the window itself is empty vs. the status filter is the problem.
if (failures.length === 0) {
  let allCount = 0;
  let sampleStatuses = [];
  try {
    const allRows = await fetchAllForStatus.call(this, 'All');
    allCount = allRows.length;
    sampleStatuses = [...new Set(allRows.map(r => r.status))].slice(0, 10);
  } catch (e) {}
  return [{ json: {
    hasErrors:false, errorCount:0, totalCount:0,
    window:`${fromDate} - ${toDate}`, portalTz,
    webhookUrl:input.teamsWebhookUrl, items:[],
    _diagnostic: {
      ...diag,
      allStatusQueryCount: allCount,
      distinctStatusesSeen: sampleStatuses,
      note: 'If allStatusQueryCount > 0 but perStatus are 0, the Status filter strings are wrong — check distinctStatusesSeen for the real values. If allStatusQueryCount is also 0, the date window has no transactions (widen windowMinutes).'
    }
  } }];
}

// --- list each failure individually (no grouping), enrich with detail ---
function histBody(txId) {
  return { sort:'TimeStampDisplay-asc', page:'1', pageSize:'50', group:'', filter:'', TransactionId:txId, __RequestVerificationToken:token };
}

async function fetchDetailHtml(txId) {
  const boundary = '----n8nFormBoundary' + Math.random().toString(16).slice(2);
  const body = `--${boundary}\r\nContent-Disposition: form-data; name="transactionId"\r\n\r\n${txId}\r\n--${boundary}--\r\n`;
  const r = await this.helpers.httpRequest({
    method:'POST', url: base + '/TransactionLogs/LoadTransactionLogsDetailPartialView',
    headers:{
      'Cookie':cookie,
      'Content-Type':`multipart/form-data; boundary=${boundary}`,
      '__requestverificationtoken': token,
      'X-Requested-With':'XMLHttpRequest', 'Accept':'*/*',
      'Origin':base, 'Referer':base+'/TransactionLogs/index'
    },
    body, json:false
  });
  return typeof r === 'string' ? r : '';
}

function pickField(html, label) {
  const re = new RegExp(label.replace(/[.*+?^${}()|[\]\\]/g,'\\$&') + '\\s*:?\\s*</label>\\s*<span[^>]*>([\\s\\S]*?)</span>', 'i');
  const m = html.match(re);
  if (!m) return null;
  return m[1].replace(/<[^>]+>/g,'').replace(/\s+/g,' ').trim() || null;
}

// safety cap so a huge error burst can't run forever / exhaust memory
const MAX_DETAIL = 50;
const list = [];
for (let i = 0; i < failures.length; i++) {
  const f = failures[i];
  const txId = f.transactionId;
  let reason = '';
  let detail = {};
  if (i < MAX_DETAIL) {
    try {
      const hist = await post.call(this, histUrl, histBody(txId));
      const steps = (hist && (hist.Data||hist.data)) || [];
      const errLine = steps.find(s => (s.logLevel||'').toLowerCase() === 'error');
      if (errLine) reason = errLine.message;
    } catch (e) { reason = 'history error: ' + (e.message||e); }
    try {
      const html = await fetchDetailHtml.call(this, txId);
      detail = {
        statusCode: pickField(html, 'Status Code'),
        httpMethod: pickField(html, 'Http Method'),
        path: pickField(html, 'Path'),
        host: pickField(html, 'Host')
      };
    } catch (e) {}
  } else {
    reason = '(detail skipped — over ' + MAX_DETAIL + ' failures)';
  }
  if (reason.length > 500) reason = reason.slice(0,500) + '\u2026';
  list.push({
    transactionId: txId,
    transactionType: f.transactionType || 'Unknown',
    status: f.status || 'Error',
    timestamp: f.Timestamp || f.startedAt || '',
    reason, detail
  });
}

return [{ json: { hasErrors:true, errorCount:failures.length, totalCount:failures.length, window:`${fromDate} - ${toDate}`, portalTz, webhookUrl:input.teamsWebhookUrl, items:list } }];

// Build the Teams MessageCard listing each failed transaction (no grouping).
const d = $input.first().json;

let card;
if (!d.hasErrors) {
  card = {
    '@type':'MessageCard', '@context':'http://schema.org/extensions',
    themeColor:'2EB67D', summary:'CommonWell: all clear',
    title:'\u2705 CommonWell: no errors',
    sections:[{ facts:[
      { name:'Window', value:`${d.window} (${d.portalTz||'ET'})` }
    ]}]
  };
} else {
  const sections = (d.items||[]).map(it => {
    const det = it.detail || {};
    const lines = [];
    if (det.statusCode) lines.push('HTTP ' + det.statusCode + (det.httpMethod ? ' (' + det.httpMethod + ')' : ''));
    if (det.path) lines.push('Path: ' + det.path);
    if (det.host) lines.push('Host: ' + det.host);
    if (it.reason) lines.push(it.reason);
    const ctx = lines.length ? '```\n' + lines.join('\n') + '\n```' : '';
    return {
      activityTitle: `**${it.transactionType}** \u2014 ${it.status}`,
      activitySubtitle: `${it.timestamp}  \u00b7  ${it.transactionId}`,
      text: ctx
    };
  });
  card = {
    '@type':'MessageCard', '@context':'http://schema.org/extensions',
    themeColor:'D70000',
    summary:`CommonWell: ${d.errorCount} failed transactions`,
    title:`\u26a0\ufe0f CommonWell: ${d.errorCount} failed transaction(s)`,
    sections:[{ facts:[
      { name:'Window', value:`${d.window} (${d.portalTz||'ET'})` },
      { name:'Failed', value:String(d.errorCount) }
    ]}].concat(sections)
  };
}

return [{ json: { hasErrors:d.hasErrors, webhookUrl:d.webhookUrl, teamsCard:card } }];
